// Generated by encrypt-key.mjs
const TRAKT_ENCODED_KEY = {"salt":"klYpRInm/JtTWZc/zmwKcQ==","iv":"r2sUoMw2WNrYwXNm","data":"EFJEKXfoquT8dblEPRuw/zf05KqvjEf2QnynnE0xcT4/r9fAO4eegt51NYIRY84QjKG5oBxx/Ur0R3bP88BmNk8+6uELodb3+iSy1zxeNyk="};
const TMDB_ENCODED_KEY = {"salt":"0UwWowwSjsJMU4POKsV4Ig==","iv":"+bx/lXgl60BWzgFL","data":"5Gvc3sQEAjej4g9SmeU0lufPuU6jJZ/kDQZ8ojZd7u2KEY5Kzf5Lhr3WoyAIS0X0"};

let trakt_client_secret_value = null;

let cached_tmdb_key_promise = Promise.resolve(null);
async function tmdb_api_key() {
  return await cached_tmdb_key_promise ||
    await (cached_tmdb_key_promise = decrypt_key(TMDB_ENCODED_KEY));
}

async function decrypt_key(encrypted_key) {
  const passphrase_key = 'easytv.passphrase';
  let passphrase = localStorage.getItem(passphrase_key);
  if (!passphrase) {
    passphrase = prompt('Enter site password:');
    if (!passphrase) return null;
  }
  try {
    const enc = new TextEncoder();
    const from_b64 = s => Uint8Array.from(atob(s), c => c.charCodeAt(0));
    const key_material = await crypto.subtle.importKey(
      'raw', enc.encode(passphrase), 'PBKDF2', false, ['deriveKey']);
    const key = await crypto.subtle.deriveKey(
      { name: 'PBKDF2', salt: from_b64(encrypted_key.salt), iterations: 100000, hash: 'SHA-256' },
      key_material, { name: 'AES-GCM', length: 256 }, false, ['decrypt']);
    const decrypted = await crypto.subtle.decrypt(
      { name: 'AES-GCM', iv: from_b64(encrypted_key.iv) },
      key, from_b64(encrypted_key.data));
    const decoded_key = new TextDecoder().decode(decrypted);
    localStorage.setItem(passphrase_key, passphrase);
    return decoded_key;
  } catch {
    localStorage.removeItem(passphrase_key);
    alert('Wrong passphrase');
    return null; // wrong passphrase
  }
}

async function tmdb_get(path) {
  const api_key = await tmdb_api_key();
  const separator = path.includes("?") ? "&" : "?";
  const response = await fetch(`${TMDB_API_BASE}${path}${separator}api_key=${api_key}`);
  if (!response.ok) throw new Error(`TMDB API error ${response.status}`);
  return response.json();
}

async function trakt_get(path, access_token) {
  const response = await fetch(`${TRAKT_API_BASE}${path}`, {
    headers: { "Content-Type": "application/json",
	       "Authorization": `Bearer ${access_token}`,
	       "trakt-api-version": "2",
	       "trakt-api-key": TRAKT_CLIENT_ID,
	     }
    
  });
  if (response.status === 401) throw new AuthError("Token expired or invalid");
  if (!response.ok) throw new Error(`Trakt API error ${response.status}`);
  return response.json();
}

async function trakt_authed(method, path, params = null) {
  const response = await fetch(`${TRAKT_API_BASE}${path}`, {
    method,
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${current_access_token}`,
      "trakt-api-version": "2",
      "trakt-api-key": TRAKT_CLIENT_ID,
    },
    body: params ? JSON.stringify(params) : undefined,
  });
  if (response.status === 401) throw new AuthError("Token expired or invalid");
  if (!response.ok) {
    const body = await response.text().catch(() => "");
    throw new Error(`Trakt API error ${response.status}: ${body}`);
  }
  if (response.status === 204) return null;
  return response.json();
}

const trakt_post_authed = (path, params) => trakt_authed("POST", path, params);

async function trakt_post (path, params) {
  return await fetch(`${TRAKT_API_BASE}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(params),
  });
}

class AuthError extends Error {};

let current_access_token = null;


// --- Auth / device flow ---

const trakt_access_token_key = "easytv.trakt_access_token";

async function start_device_flow() {
  const response = await trakt_post("/oauth/device/code", { client_id: TRAKT_CLIENT_ID });
  if (!response.ok) throw new Error("Failed to start device flow");
  return response.json();
}

async function poll_for_token(device_code, interval_seconds) {
  let poll_interval = (interval_seconds ?? 5) * 1000;
  while (true) {
    await new Promise(resolve => setTimeout(resolve, poll_interval));
    const response = await trakt_post("/oauth/device/token", {
      code: device_code,
      client_id: TRAKT_CLIENT_ID,
      client_secret: trakt_client_secret_value
    });
    if (response.status === 200) return response.json();
    // TODO: refresh it!!
    if (response.status === 410) throw new Error("Login code expired. Please try again.");
    if (response.status === 418) throw new Error("Authorization denied.");
    if (response.status === 429) { poll_interval *= 2; continue; }
    // 400 = pending, 409 = already used
    if (response.status === 400 || response.status === 409) continue;
    throw new Error(`Unexpected response ${response.status} while waiting for authorization`);
  }
}

// --- Notes API ---


const trakt_notes = (() => {
  const cache = new Map(); // show_id -> { note_id, text }
  let load_promise = null;

  function load_all() {
    if (!load_promise) {
      load_promise = trakt_get("/users/me/notes/shows", current_access_token)
        .then(items => {
          for (const item of items) {
            cache.set(item.show.ids.trakt, { note_id: item.note.id, text: item.note.notes });
          }
        }).catch(() => {});
    }
    return load_promise;
  }

  return {
    load_all,
    reset() { cache.clear(); load_promise = null; },
    async get(show_id) {
      await load_all();
      return cache.get(show_id)?.text ?? "";
    },
    async set(show_id, text) {
      await load_all();
      const existing = cache.get(show_id);
      if (!text.trim()) {
        if (existing) {
          await trakt_authed("DELETE", `/notes/${existing.note_id}`);
          cache.delete(show_id);
        }
      } else if (existing) {
        await trakt_authed("PUT", `/notes/${existing.note_id}`, { notes: text });
        existing.text = text;
      } else {
        const result = await trakt_authed("POST", "/notes", {
          notes: text, show: { ids: { trakt: show_id } }
        });
        cache.set(show_id, { note_id: result.id, text });
      }
    },
  };
})();

const notes = trakt_notes;

function sort_title(title) {
  return title.replace(/^(A|The) /i, "");
}

// --- Rendering ---

let current_open_show = null;

function render_show_row(item) {
  const { show } = item;
  const unseen_count = (show.aired_episodes ?? 0) - item.watched_count;

  const row_div = document.createElement("div");
  row_div.className = "show-row";

  // Header (always visible, clickable)
  const header_div = document.createElement("div");
  header_div.className = "show-header";

  const poster_img = document.createElement("img");
  poster_img.className = "show-poster-thumb";
  poster_img.alt = show.title;

  const info_div = document.createElement("div");
  info_div.className = "show-info";

  const title_line = document.createElement("div");
  title_line.className = "show-title-line";
  const title_text = document.createElement("span");
  title_text.textContent = show.title;

  const note_input = document.createElement("input");
  note_input.type = "text";
  note_input.className = "show-note";
  note_input.placeholder = "add note…";
  notes.get(show.ids.trakt).then(text => { note_input.value = text; });

  let note_saved_value = "";
  note_input.addEventListener("focus", () => { note_saved_value = note_input.value; });
  note_input.addEventListener("blur", () => {
    if (note_input.value !== note_saved_value) {
      notes.set(show.ids.trakt, note_input.value);
    }
  });
  note_input.addEventListener("keydown", e => { if (e.key === "Enter") note_input.blur(); });
  note_input.addEventListener("click", e => e.stopPropagation());

  title_line.append(title_text, note_input);

  const next_line = document.createElement("div");
  next_line.className = "show-next-line";
  next_line.textContent = `${unseen_count} episode${unseen_count !== 1 ? "s" : ""} left`;

  const network_line = document.createElement("div");
  network_line.className = "show-network-line";
  network_line.textContent = show.network ?? "";

  info_div.append(title_line, next_line, network_line);
  const meta_parts = [show.year, show.status].filter(Boolean);
  const meta_suffix = meta_parts.length ? ` (${meta_parts.join(", ")})` : "";
  const overview_text = (show.overview ?? "") + meta_suffix;
  if (overview_text) {
    const overview_line = document.createElement("div");
    overview_line.className = "show-overview-line";
    overview_line.textContent = overview_text;
    info_div.appendChild(overview_line);
  }
  header_div.append(poster_img, info_div);
  row_div.appendChild(header_div);

  // Expanded content
  const expanded_div = document.createElement("div");
  expanded_div.className = "show-expanded";
  expanded_div.hidden = true;
  row_div.appendChild(expanded_div);

  // Fetch progress eagerly — used for "Up next" and for expanding seasons
  const progress_promise = trakt_get(
    `/shows/${show.ids.trakt}/progress/watched?extended=full`,
    current_access_token
  ).then(progress => {
    if (progress.next_episode) {
      const ep = progress.next_episode;
      next_line.textContent = `Up next S${ep.season}E${ep.number} — ${unseen_count} episode${unseen_count !== 1 ? "s" : ""} left`;
    }
    return progress;
  }).catch(() => null);

  row_div._refresh_header = async () => {
    try {
      const progress = await trakt_get(
        `/shows/${show.ids.trakt}/progress/watched`,
        current_access_token
      );
      const unseen = (progress.aired ?? 0) - (progress.completed ?? 0);
      if (progress.next_episode) {
        const ep = progress.next_episode;
        next_line.textContent = `Up next S${ep.season}E${ep.number} — ${unseen} episode${unseen !== 1 ? "s" : ""} left`;
      } else {
        next_line.textContent = unseen > 0 ? `${unseen} episode${unseen !== 1 ? "s" : ""} left` : "All caught up!";
      }
    } catch {}
  };

  // Fetch poster eagerly
  if (show.ids.tmdb) {
    tmdb_get(`/tv/${show.ids.tmdb}`).then(tmdb => {
      if (tmdb.poster_path) {
        poster_img.src = `${TMDB_IMAGE_BASE}/w92${tmdb.poster_path}`;
      }
    }).catch(() => {});
  }

  // Click to expand/collapse
  let seasons_rendered = false;
  header_div.addEventListener("click", async () => {
    const opening = expanded_div.hidden;

    if (current_open_show && current_open_show !== expanded_div) {
      current_open_show.hidden = true;
      current_open_show.closest(".show-row").classList.remove("open");
    }
    current_open_show = opening ? expanded_div : null;

    expanded_div.hidden = !opening;
    row_div.classList.toggle("open", opening);
    if (!expanded_div.hidden && !seasons_rendered) {
      seasons_rendered = true;
      const loading = document.createElement("div");
      loading.textContent = "Loading…";
      expanded_div.appendChild(loading);
      try {
        const progress = await progress_promise;
        loading.remove();
        if (progress) {
          let first_unseen_season_shown = false;
          for (const season of progress.seasons) {
            const has_unseen = (season.aired - season.completed) > 0;
            const auto_open = has_unseen && !first_unseen_season_shown;
            if (auto_open) first_unseen_season_shown = true;
            expanded_div.appendChild(render_season_row(season, show.ids.trakt, auto_open));
          }
        }
      } catch (error) {
        loading.textContent = `Error loading progress: ${error.message}`;
      }
    }
  });

  return row_div;
}

function render_season_row(season, show_id, auto_open = false) {
  const details = document.createElement("details");
  details.className = "season-row";
  const summary = document.createElement("summary");
  summary.className = "season-summary";
  const season_label = season.number === 0 ? "Specials" : `Season ${season.number}`;
  summary.dataset.seasonLabel = season_label;
  const unseen_count = season.aired - season.completed;
  if (unseen_count > 0) summary.style.fontWeight = "bold";
  const count_label = unseen_count > 0 ? ` (${season.completed} seen, ${unseen_count} unseen)` : "";
  summary.textContent = `${season_label}${count_label}`;
  details.appendChild(summary);

  const episodes_div = document.createElement("div");
  episodes_div.className = "episodes-list";
  details.appendChild(episodes_div);

  const completion_by_number = new Map(season.episodes.map(ep => [ep.number, ep]));
  let episodes_loaded = false;
  details.addEventListener("toggle", async () => {
    if (!details.open || episodes_loaded) return;
    episodes_loaded = true;
    episodes_div.textContent = "Loading…";
    try {
      const episode_details = await trakt_get(
        `/shows/${show_id}/seasons/${season.number}?extended=full`,
        current_access_token
      );
      episodes_div.textContent = "";
      let first_unseen_shown = false;
      for (const ep of episode_details) {
        const progress = completion_by_number.get(ep.number) ?? { completed: false };
        const merged = { ...progress, ...ep };
        const auto_open = !merged.completed && !first_unseen_shown;
        if (auto_open) first_unseen_shown = true;
        episodes_div.appendChild(render_episode_row(merged, auto_open));
      }
    } catch (error) {
      episodes_div.textContent = `Error loading episodes: ${error.message}`;
    }
  });

  if (auto_open) details.open = true;

  return details;
}

function render_episode_row(episode, auto_open = false) {
  const div = document.createElement("div");
  div.className = `episode-row ${episode.completed ? "watched" : "unwatched"}`;
  const ep_num = `E${String(episode.number).padStart(2, "0")}`;
  const ep_text = `${ep_num}${episode.title ? ` — ${episode.title}` : ""}`;

  const checkbox = document.createElement("input");
  checkbox.type = "checkbox";
  checkbox.className = "episode-checkbox";
  checkbox.checked = !!episode.completed;
  checkbox.addEventListener("change", async () => {
    checkbox.disabled = true;
    try {
      if (checkbox.checked) {
        await trakt_post_authed("/sync/history", { episodes: [{ ids: { trakt: episode.ids.trakt } }] });
      } else {
        await trakt_post_authed("/sync/history/remove", { episodes: [{ ids: { trakt: episode.ids.trakt } }] });
      }
      const watched = checkbox.checked;
      div.className = `episode-row ${watched ? "watched" : "unwatched"}`;
      const color = watched ? "#888" : "#000";
      div.querySelectorAll(".episode-summary, .episode-overview").forEach(el => {
        el.style.color = color;
      });
      if (watched) {
        const details = div.querySelector("details");
        if (details) details.open = false;
      }
      const episodes_list = div.closest(".episodes-list");
      if (episodes_list) {
        const first_unseen = Array.from(episodes_list.querySelectorAll(".episode-row"))
          .find(row => !row.querySelector(".episode-checkbox").checked);
        if (first_unseen) {
          const details = first_unseen.querySelector("details");
          if (details) details.open = true;
        }
      }
      const season_row = div.closest(".season-row");
      if (season_row) {
        const checkboxes = Array.from(season_row.querySelectorAll(".episode-checkbox"));
        const seen = checkboxes.filter(cb => cb.checked).length;
        const unseen = checkboxes.length - seen;
        const season_summary = season_row.querySelector("summary.season-summary");
        season_summary.style.fontWeight = unseen > 0 ? "bold" : "normal";
        const label = season_summary.dataset.seasonLabel;
        season_summary.textContent = unseen > 0 ? `${label} (${seen} seen, ${unseen} unseen)` : label;
      }
      div.closest(".show-row")?._refresh_header?.();
    } catch (error) {
      checkbox.checked = !checkbox.checked;
    } finally {
      checkbox.disabled = false;
    }
  });

  if (episode.overview) {
    const details = document.createElement("details");
    if (auto_open) details.open = true;
    const summary = document.createElement("summary");
    summary.className = "episode-summary";
    summary.style.color = episode.completed ? "#888" : "#000";
    const label = document.createElement("span");
    label.textContent = ep_text;
    summary.append(checkbox, label);
    const overview = document.createElement("div");
    overview.className = "episode-overview";
    overview.style.color = episode.completed ? "#888" : "#000";
    overview.textContent = episode.overview;
    details.append(summary, overview);
    div.appendChild(details);
  } else {
    const label = document.createElement("span");
    label.textContent = ep_text;
    div.append(checkbox, label);
  }

  return div;
}

// --- Views ---

function show_login_view() {
  document.getElementById("login-section").hidden = false;
  document.getElementById("watchlist-section").hidden = true;
  document.getElementById("user-info").innerHTML = "";
}


function show_watchlist_view() {
  document.getElementById("login-section").hidden = true;
  document.getElementById("watchlist-section").hidden = false;
}

function show_code_dialog(user_code, verification_url) {
  return new Promise((resolve, reject) => {
    const dialog = document.getElementById("login-code-dialog");
    const code_el = document.getElementById("dialog-code");
    const copied_el = document.getElementById("dialog-copied");
    const ok_btn = document.getElementById("dialog-ok");
    const cancel_btn = document.getElementById("dialog-cancel");

    code_el.textContent = user_code;
    copied_el.hidden = true;
    navigator.clipboard.writeText(user_code).then(() => { copied_el.hidden = false; }).catch(() => {});

    ok_btn.onclick = () => { dialog.close(); resolve(); };
    cancel_btn.onclick = () => { dialog.close(); reject(new Error("Login cancelled")); };
    dialog.oncancel = () => reject(new Error("Login cancelled"));

    dialog.showModal();
  });
}

async function run_device_login() {
  const status_el = document.getElementById("login-status");
  const login_btn = document.getElementById("login-btn");

  login_btn.disabled = true;
  status_el.textContent = "Starting login…";
  status_el.className = "";

  try {
    const device = await start_device_flow();

    await show_code_dialog(device.user_code, device.verification_url);

    const popup_width = 520;
    const popup_height = 600;
    const popup_left = window.screenX + Math.round((window.outerWidth - popup_width) / 2);
    const popup_top = window.screenY + Math.round((window.outerHeight - popup_height) / 2);
    const auth_popup = window.open(device.verification_url, "trakt-auth",
      `width=${popup_width},height=${popup_height},left=${popup_left},top=${popup_top}`);

    status_el.textContent = "Waiting for authorization…";

    const token_data = await poll_for_token(device.device_code, device.interval);
    if (auth_popup && !auth_popup.closed) auth_popup.close();
    status_el.textContent = "";
    localStorage.setItem(trakt_access_token_key, token_data.access_token);
    await load_watchlist(token_data.access_token);
  } catch (error) {
    status_el.textContent = error.message;
    status_el.className = "error";
  } finally {
    login_btn.disabled = false;
  }
}

async function load_watchlist(access_token) {
  current_access_token = access_token;
  current_open_show = null;
  trakt_notes.reset();
  trakt_notes.load_all();
  show_watchlist_view();
  const status_el = document.getElementById("watchlist-status");
  const grid_el = document.getElementById("shows-grid");

  status_el.textContent = "Loading…";
  grid_el.innerHTML = "";

  try {
    const [profile, watchlist_items, watched_items] = await Promise.all([
      trakt_get("/users/me", access_token),
      trakt_get("/users/me/watchlist/shows?extended=full", access_token),
      trakt_get("/users/me/watched/shows?extended=full", access_token),
    ]);

    const hidden_items = await trakt_get("/users/hidden/progress_watched?type=show&limit=1000", access_token)
      .catch(e => { console.warn("Hidden shows fetch failed:", e.message); return []; });
    const hidden_ids = new Set(hidden_items.map(item => item.show.ids.trakt));

    // Build union keyed by trakt show ID
    const shows_by_id = new Map();

    for (const item of watchlist_items) {
      shows_by_id.set(item.show.ids.trakt, {
        show: item.show,
        listed_at: item.listed_at,
        watched_count: 0,
      });
    }

    for (const item of watched_items) {
      const watched_count = item.seasons.reduce(
        (total, season) => total + season.episodes.length, 0
      );
      const existing = shows_by_id.get(item.show.ids.trakt);
      if (existing) {
        existing.watched_count = watched_count;
      } else {
        shows_by_id.set(item.show.ids.trakt, {
          show: item.show,
          listed_at: item.last_watched_at,
          watched_count,
        });
      }
    }

    // Only shows with unwatched aired episodes, sorted by title
    const shows = Array.from(shows_by_id.values())
      .filter(item => !hidden_ids.has(item.show.ids.trakt))
      .filter(item => (item.show.aired_episodes ?? 0) > item.watched_count)
      .sort((a, b) => sort_title(a.show.title).localeCompare(sort_title(b.show.title)));

    const logout_btn = document.createElement("button");
    logout_btn.id = "logout-btn";
    logout_btn.textContent = "Log out";
    logout_btn.addEventListener("click", () => {
      localStorage.removeItem(trakt_access_token_key);
      show_login_view();
    });

    const user_info_el = document.getElementById("user-info");
    user_info_el.textContent = profile.username + " ";
    user_info_el.appendChild(logout_btn);

    status_el.textContent = `${shows.length} show${shows.length !== 1 ? "s" : ""}`;
    for (const item of shows) {
      grid_el.appendChild(render_show_row(item));
    }
  } catch (error) {
    if (error instanceof AuthError) {
      localStorage.removeItem(trakt_access_token_key);
      show_login_view();
      document.getElementById("login-status").textContent = "Session expired. Please log in again.";
    } else {
      status_el.textContent = error.message;
      status_el.className = "error";
    }
  }
}

// --- Init ---

document.getElementById("login-btn").addEventListener("click", run_device_login);

(async () => {
  trakt_client_secret_value = await decrypt_key(TRAKT_ENCODED_KEY);
  if (!trakt_client_secret_value) {
    document.getElementById("login-btn").hidden = true;
    document.getElementById("login-status").textContent = "Passphrase required to use this app.";
    document.getElementById("login-status").className = "error";
    document.getElementById("login-section").hidden = false;
    return;
  }
  const stored_token = localStorage.getItem(trakt_access_token_key);
  if (stored_token) {
    load_watchlist(stored_token);
  } else {
    show_login_view();
  }
})();
